## Testing Requirements

### Unit Tests (`apps/gateway/tests/unit/ru-schema.test.ts`)

```typescript
describe("RU Schema", () => {
  describe("fleetRepos table", () => {
    it("should insert and retrieve all fields correctly", async () => {
      const repo: FleetRepo = {
        id: "repo_test_001",
        owner: "test-org",
        name: "test-repo",
        fullName: "test-org/test-repo",
        url: "https://github.com/test-org/test-repo.git",
        isCloned: true,
        localPath: "/repos/test-org/test-repo",
        currentBranch: "main",
        defaultBranch: "main",
        status: "healthy",
        hasUncommittedChanges: false,
        hasUnpushedCommits: false,
        aheadBy: 0,
        behindBy: 0,
        addedAt: new Date(),
      };

      await db.insert(fleetRepos).values(repo);
      const retrieved = await db.select().from(fleetRepos).where(eq(fleetRepos.id, repo.id));

      expect(retrieved[0].fullName).toBe(repo.fullName);
      expect(retrieved[0].status).toBe("healthy");

      logger.info({
        testName: "fleet_repos_insert_retrieve",
        repoId: repo.id,
        correlationId: getCorrelationId(),
      }, "Fleet repo insert/retrieve test passed");
    });

    it("should enforce unique fullName constraint", async () => {
      await db.insert(fleetRepos).values({
        id: "repo_1",
        owner: "org",
        name: "repo",
        fullName: "org/repo",
        url: "https://github.com/org/repo.git",
      });

      await expect(
        db.insert(fleetRepos).values({
          id: "repo_2",
          owner: "org",
          name: "repo",
          fullName: "org/repo",  // Duplicate
          url: "https://github.com/org/repo.git",
        })
      ).rejects.toThrow();

      logger.info({
        testName: "fleet_repos_unique_constraint",
        correlationId: getCorrelationId(),
      }, "Unique constraint enforced");
    });
  });

  describe("agentSweepSessions table", () => {
    it("should track phase progression", async () => {
      const session = {
        id: "sweep_test_001",
        targetRepos: JSON.stringify(["repo1", "repo2"]),
        repoCount: 2,
        status: "running",
        currentPhase: "phase1_analysis",
      };

      await db.insert(agentSweepSessions).values(session);

      // Update to phase 2
      await db.update(agentSweepSessions)
        .set({
          currentPhase: "phase2_planning",
          phase1CompletedAt: sql`(unixepoch())`,
        })
        .where(eq(agentSweepSessions.id, session.id));

      const updated = await db.select()
        .from(agentSweepSessions)
        .where(eq(agentSweepSessions.id, session.id));

      expect(updated[0].currentPhase).toBe("phase2_planning");
      expect(updated[0].phase1CompletedAt).not.toBeNull();

      logger.info({
        testName: "sweep_phase_progression",
        sessionId: session.id,
        phase: updated[0].currentPhase,
        correlationId: getCorrelationId(),
      }, "Phase progression tracked");
    });
  });

  describe("agentSweepPlans table", () => {
    it("should store and retrieve JSON plan", async () => {
      const plan = {
        id: "plan_test_001",
        sessionId: "sweep_test_001",
        repoFullName: "test-org/test-repo",
        planJson: JSON.stringify({
          actions: [
            { type: "commit", message: "Update dependencies" },
            { type: "release", version: "1.2.3" },
          ],
        }),
        actionCount: 2,
        riskLevel: "low",
        approvalStatus: "pending",
      };

      await db.insert(agentSweepPlans).values(plan);

      const retrieved = await db.select()
        .from(agentSweepPlans)
        .where(eq(agentSweepPlans.id, plan.id));

      const parsedPlan = JSON.parse(retrieved[0].planJson);
      expect(parsedPlan.actions).toHaveLength(2);

      logger.info({
        testName: "sweep_plan_json_storage",
        planId: plan.id,
        actionCount: parsedPlan.actions.length,
        correlationId: getCorrelationId(),
      }, "Plan JSON stored and retrieved");
    });
  });

  describe("indexes", () => {
    it("should have indexes for query performance", async () => {
      const repoIndexes = await getTableIndexes(db, "fleet_repos");
      expect(repoIndexes).toContainEqual(expect.objectContaining({ name: "fleet_repos_owner_idx" }));
      expect(repoIndexes).toContainEqual(expect.objectContaining({ name: "fleet_repos_status_idx" }));

      const sessionIndexes = await getTableIndexes(db, "agent_sweep_sessions");
      expect(sessionIndexes).toContainEqual(expect.objectContaining({ name: "agent_sweep_sessions_status_idx" }));

      logger.info({
        testName: "index_verification",
        correlationId: getCorrelationId(),
      }, "All indexes verified");
    });
  });
});
```

