describe("RU Schema Integration", () => {
  it("should cascade sweep session to plans and logs", async () => {
    // Create session
    const session = await createSweepSession({
      targetRepos: ["repo1", "repo2"],
      triggeredBy: "test",
    });

    // Create plans for session
    await createSweepPlan({
      sessionId: session.id,
      repoFullName: "org/repo1",
      planJson: { actions: [] },
    });

    // Create logs for session
    await createSweepLog({
      sessionId: session.id,
      phase: "phase1",
      level: "info",
      message: "Started analysis",
    });

    // Query with joins
    const sessionWithPlans = await db.query.agentSweepSessions.findFirst({
      where: eq(agentSweepSessions.id, session.id),
      with: {
        plans: true,
        logs: true,
      },
    });

    expect(sessionWithPlans?.plans).toHaveLength(1);
    expect(sessionWithPlans?.logs).toHaveLength(1);

    logger.info({
      testName: "session_cascade",
      sessionId: session.id,
      planCount: sessionWithPlans?.plans.length,
      logCount: sessionWithPlans?.logs.length,
      correlationId: getCorrelationId(),
    }, "Session cascade verified");
  });
});
```

